use std::collections::HashMap;
use std::net::{SocketAddr, IpAddr, Ipv4Addr};

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
struct ConnectionKey {
    ip: IpAddr,
    port: u16,
}

#[derive(Debug, Clone)]
struct SessionObject {
    is_active: bool,
    last_seen: std::time::Instant,
}

fn manage_connections() -> HashMap<ConnectionKey, SessionObject> {
    let mut registry = HashMap::new();

    let ip1: IpAddr = Ipv4Addr::new(192, 168, 1, 1).into();
    let key1 = ConnectionKey { ip: ip1, port: 5000 };
    registry.insert(key1, SessionObject { is_active: true, last_seen: std::time::Instant::now() });

    let ip2: IpAddr = Ipv4Addr::new(192, 168, 1, 2).into();
    let key2 = ConnectionKey { ip: ip2, port: 5000 };
    registry.insert(key2, SessionObject { is_active: false, last_seen: std::time::Instant::now() - std::time::Duration::from_secs(3600) });

    let key3 = ConnectionKey { ip: ip1, port: 5001 };
    registry.entry(ConnectionKey { ip: ip1, port: 5001 }).or_insert_with(|| {
        SessionObject { is_active: false, last_seen: std::time::Instant::now() }
    });

    let mut key1_mut = ConnectionKey { ip: ip1, port: 5000 };
    key1_mut.port = 5000;
    if let Some(entry) = registry.get_mut(&key1_mut) {
        entry.last_seen = std::time::Instant::now();
    }

    println!("Successfully indexed {} connection records.", registry.len());
    registry
}

fn main() {
    let _connections = manage_connections();
}

use std::collections::HashMap;

struct SensorData {
    readings: Vec<f64>,
    average: f64,
}

fn calculate_running_stats(sensor_map: &mut HashMap<String, SensorData>, new_reading: String) -> HashMap<String, (f64, f64)> {
    let sensor_name = new_reading.clone();
    let reading: f64 = new_reading.parse().unwrap_or(0.0);

    sensor_map.entry(sensor_name.to_string()).or_insert_with(|| SensorData{readings: Vec::new(), average: 0.0});

    if let Some(data) = sensor_map.get_mut(&sensor_name)
    {
        data.readings.push(reading);
        let sum: f64 = data.readings.iter().sum();
        data.average = sum / (data.readings.len() as f64);
    }

    let mut results = HashMap::new();
    for (name, data) in sensor_map.iter_mut() {
        results.insert(name.clone(), (reading, data.average));
    }
    results
}

fn main() {
    let mut sensor_readings: HashMap<String, SensorData> = HashMap::new();

    calculate_running_stats(&mut sensor_readings, "Temperature_A 22.5".to_string());
    println!("Initial state after first reading.");

    let mut results = calculate_running_stats(&mut sensor_readings, "Humidity_B 60.1".to_string());
    println!("Results after second reading: {:#?}", results);

    calculate_running_stats(&mut sensor_readings, "Temperature_A 23.0".to_string());
    results = calculate_running_stats(&mut sensor_readings, "Humidity_B 61.5".to_string());
    println!("Results after third reading: {:#?}", results);
}

use std::collections::HashMap;
use std::io::{self, Write};

struct ButtonTracker {
    click_counts: HashMap<String, u32>,
}

impl ButtonTracker {
    fn new() -> Self {
        ButtonTracker {
            click_counts: HashMap::new(),
        }
    }

    fn record_click(&mut self, button_name: &str) {
        *self.click_counts.entry(button_name.to_string()).or_insert(0) += 1;
    }

    fn display_summary(&self) -> String {
        let mut summary = "Button Click Summary:n".to_string();
        for (name, count) in &self.click_counts {
            summary.push_str(&format!("  - {}: {} timesn", name, count));
        }
        summary
    }
}

fn main() -> io::Result<()> {
    let mut tracker = ButtonTracker::new();

    tracker.record_click("SaveButton");
    tracker.record_click("OpenButton");
    tracker.record_click("SaveButton");
    tracker.record_click("RefreshButton");
    tracker.record_click("OpenButton");

    print!("Simulated clicks recorded successfully. Press Enter to see the total:n");
    io::stdout().flush()?;
    let mut buffer = String::new();
    io::stdin().read_line(&mut buffer)?;

    println!("n{}", tracker.display_summary());

    Ok(())
}

use std::collections::HashMap;
use std::io::{self, Write, BufRead};

fn main() -> io::Result<()>{
    let mut settings_map: HashMap<String, String> = HashMap::new();
    let mut handle = io::stdout().lock();

    writeln!(handle, "Enter key-value pairs, one per line (format: key=value). Press Ctrl+D when done.");

    let stdin = io::stdin();
    let mut lines = stdin.lock().lines();

    while let Some(line_result) = lines.next() {
        let line = line_result?;
        if line.trim().is_empty() { continue; }

        match line.split_once('=') {
            Some((key, value)) => {
                let key_str = key.to_string();
                let value_str = value.to_string();
                settings_map.insert(key_str, value_str);
            }
            None => {
                eprintln!("Error: Line must be in 'key=value' format. Skipping line: {}", line);
            }
        }
    }

    writeln!(handle, "n--- Processing Complete ---");

    for (key, value) in settings_map.iter() {
        writeln!(handle, "Setting: {}: {}", key, value).unwrap();
    }

    if settings_map.is_empty() { 
        writeln!(handle, "No valid settings were entered.").unwrap();
    }

    Ok(())
}

use std::collections::HashMap;

struct PluginSandbox {
    loaded_plugins: HashMap<String, bool>,
}

impl PluginSandbox {
    fn new() -> Self {
        PluginSandbox {
            loaded_plugins: HashMap::new(),
        }
    }

    fn mark_plugin_loaded(&mut self, plugin_id: &str) {
        self.loaded_plugins.insert(String::from(plugin_id), true);
    }

    fn check_if_loaded(&self, plugin_id: &str) -> bool {
        self.loaded_plugins.get(plugin_id).map(|v| *v).unwrap_or(false)
    }
}

fn main() {
    let mut sandbox = PluginSandbox::new();
    sandbox.mark_plugin_loaded("wasm_auth_v1");

    println!("Is auth loaded? {}", sandbox.check_if_loaded("wasm_auth_v1"));
    println!("Is network loaded? {}", sandbox.check_if_loaded("wasm_network_v2"));
}
